form:Form.form:Scripts:
		function validate()
{ 
	if(Ctrl('e_antig_desde').TypedValue() != null && Ctrl('e_antig_hasta').TypedValue() != null)
	{
		if(Ctrl('e_antig_desde').TypedValue() >= Ctrl('e_antig_hasta').TypedValue())
		{
			alert('La cantidad de Meses de Antigüedad Desde debe ser menor a la cantidad de Meses de Antigüedad Hasta');
			Ctrl('e_antig_hasta').SetXValue('');
		}
	}
}
